local function encrypt(str)local r=""for i=1,#str do local b=s.byte(str,i)r=r..s.format("%02X",b)end return r end
local function decrypt(str)local r=""for i=1,#str,2 do local b=s.sub(str,i,i+1)r=r..s.char(tonumber(b,16))end return r en
