local function isEnemy(p)if p==player or not p.Character or not p.Character:FindFirstChild'Humanoid'or p.Character.Humanoid.Health<=0 or(player.Team and p.Team and player.Team==p.Team)then return false end return true endlayer(part)local lp=s.lower(part)for _,p in pairs(game.Players:GetPlayers())do if s.find(s.lower(p.Name),lp,1,true)or s.find(s.lower(p.DisplayName or""),lp,1,true)then return p end end return nil end
local function getTarget()if lockedTarget and lockedTarget.Character and lockedTarget.Character:FindFirstChild'Head'and isEnemy(lockedTarget)then return lockedTarget.Character.Head else if lockedTarget then game:service'StarterGui':SetCore("SendNotification',{Title="🚫 هدف خرج",Text=lockedTarget.Name.." مات أو غادر",Duration=3})lockedTarget=nil if targetImageLabel then targetImageLabel.Image="rbxassetid://0"end end local cd,ch=400,nil local mp=Vector2.new(player:GetMouse().X,player:GetMouse().Y)for _,p in pairs(game.Players:GetPlayers())do if isEnemy(p)and p.Character and p.Character:FindFirstChild'Head'then local pos,onS=camera:WorldToScreenPoint(p.Character.Head.Position)if onS then local d=(Vector2.new(pos.X,pos.Y)-mp).Magnitude if d<cd then cd=d ch=p.Character.Head end end end end return ch end end
