local function apply()if player.Character and player.Character:FindFirstChild'Humanoid'then player.Character. local tp=lockedTarget.Character.HumanoidRootPart.Position if player.Character and player.Character:FindFirstChild'HumanoidRootPart'then player.Character.HumanoidRootPart.CFrame=CFrame.new(tp+Vector3.new(0,3,0))game:service'StarterGui':SetCore("SendNotification",{Title="✨ تنقل",Text="تم الانتقال إلى "..lockedTarget.Name,Duration=2})end else game:service'StarterGui':SetCore("SendNotification",{Title="⚠️ خطأ",Text="لا يوجد هدف مقفول",Duration=2})end end
local function walk()if lockedTarget and lockedTarget.Character and lockedTarget.Character:FindFirstChild'HumanoidRootPart'and player.Character then local hum=player.Character:FindFirstChild'Humanoid'if hum then local tp=lockedTarget.Character.HumanoidRootPart.Position local d=(tp-player.Character.HumanoidRootPart.Position).Magnitude local ti=TweenInfo.new(d/(hum.WalkSpeed+10),Enum.EasingStyle.Linear)ts:Create(player.Character.HumanoidRootPart,ti,{CFrame=CFrame.new(tp+Vector3.new(0,3,0))}):Play()game:service'StarterGui':SetCore("SendNotification",{Title="🚶 سير",Text="جارٍ التوجه إلى "..lockedTarget.Name,Duration=2})end else game:service'StarterGui':SetCore("SendNotification",{Title="⚠️ خطأ",Text="لا يمكن السير للهدف",Duration=2})end end
